            },
            {
                type: 'ai_tool',
                required: true,
            },
            {
                type: 'ai_outputParser',
            },
        ];
    }
    else if (agent === 'reActAgent') {
        specialInputs = [
            {
                type: 'ai_languageModel',
            },
            {
                type: 'ai_tool',
            },
            {
                type: 'ai_outputParser',
            },
        ];
    }
    else if (agent === 'sqlAgent') {
        specialInputs = [
            {
                type: 'ai_languageModel',
            },
            {
                type: 'ai_memory',
            },
        ];
    }
    else if (agent === 'planAndExecuteAgent') {
        specialInputs = [
            {
